#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int son[26],fail;
}tr[N];

int n,tot=1,len[N],path[N][2],w[N];
int q[N];
char s[N],t[N];
vector<int> e[N];
bool c[N];

void Insert(int x){
    int p=1;
    for(int i=0;t[i];i++){
        if(!tr[p].son[t[i]-'a'])
            tr[p].son[t[i]-'a']=++tot;
        p=tr[p].son[t[i]-'a'];
    }
    w[p]=x;
}

void dfs(int x,int fa){
    if(!w[x])
        w[x]=w[fa];
    for(int y:e[x])
        dfs(y,x);
}

void build(){
    int hh=1,tt=0;
    for(int i=0;i<26;i++)
        if(tr[1].son[i]){
            q[++tt]=tr[1].son[i];
            tr[tr[1].son[i]].fail=1;
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=q[hh++];
        e[tr[x].fail].push_back(x);
        for(int i=0;i<26;i++)
            if(tr[x].son[i]){
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
                q[++tt]=tr[x].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
    dfs(1,0);
}

void solve(){
    path[0][0]=1;
    path[0][1]=0;
    int p=1,cnt=0;
    for(int i=1;s[i];i++){
        p=tr[p].son[s[i]-'a'];
        path[++cnt][0]=p;
        path[cnt][1]=i;
        if(w[p]){
            for(int j=0;j<len[w[p]];j++){
                c[path[cnt][1]]=1;
                cnt--;
            }
            p=path[cnt][0];
        }
    }
    for(int i=1;s[i];i++)
        if(!c[i])
            printf("%c",s[i]);
}

int main(){
    scanf("%s",s+1);
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",t);
        len[i]=strlen(t);
        Insert(i);
    }
    build();
    solve();
    return 0;
}
